const pptxgen = require('pptxgenjs');
const html2pptx = require('../scripts/html2pptx');

async function createPresentation() {
    const pptx = new pptxgen();
    pptx.layout = 'LAYOUT_16x9';
    pptx.title = '热敏打印机市场分析报告';
    pptx.author = 'Market Analysis';

    // Slide 1: Cover
    await html2pptx('workspace/slide01.html', pptx);

    // Slide 2: Contents
    await html2pptx('workspace/slide02.html', pptx);

    // Chapter 1: Market Analysis
    await html2pptx('workspace/slide03.html', pptx);
    await html2pptx('workspace/slide04.html', pptx);

    // Slide 5: Regional Market with Pie Chart
    const { slide: slide5, placeholders: p5 } = await html2pptx('workspace/slide05.html', pptx);
    slide5.addChart(pptx.charts.PIE, [{
        name: "市场份额",
        labels: ["亚太地区", "北美", "欧洲", "其他"],
        values: [42, 28, 23, 7]
    }], { ...p5[0], showPercent: true, showLegend: true, legendPos: 'b', chartColors: ["1E40AF", "3B82F6", "60A5FA", "93C5FD"] });

    await html2pptx('workspace/slide06.html', pptx);
    await html2pptx('workspace/slide07.html', pptx);
    await html2pptx('workspace/slide08.html', pptx);
    await html2pptx('workspace/slide09.html', pptx);
    await html2pptx('workspace/slide10.html', pptx);
    await html2pptx('workspace/slide11.html', pptx);
    await html2pptx('workspace/slide12.html', pptx);

    // Chapter 2: Product Positioning
    await html2pptx('workspace/slide13.html', pptx);
    await html2pptx('workspace/slide14.html', pptx);
    await html2pptx('workspace/slide15.html', pptx);
    await html2pptx('workspace/slide16.html', pptx);
    await html2pptx('workspace/slide17.html', pptx);
    await html2pptx('workspace/slide18.html', pptx);
    await html2pptx('workspace/slide19.html', pptx);
    await html2pptx('workspace/slide20.html', pptx);

    // Chapter 3: Scenario Segmentation
    // Slide 21: Scenario Overview with Pie Chart
    const { slide: slide21, placeholders: p21 } = await html2pptx('workspace/slide21.html', pptx);
    slide21.addChart(pptx.charts.PIE, [{
        name: "场景分布",
        labels: ["零售收银", "餐饮外卖", "物流快递", "医疗健康", "其他"],
        values: [35, 25, 20, 10, 10]
    }], { ...p21[0], showPercent: true, showLegend: true, legendPos: 'b', chartColors: ["1E40AF", "3B82F6", "60A5FA", "93C5FD", "BFDBFE"] });

    await html2pptx('workspace/slide22.html', pptx);
    await html2pptx('workspace/slide23.html', pptx);
    await html2pptx('workspace/slide24.html', pptx);
    await html2pptx('workspace/slide25.html', pptx);
    await html2pptx('workspace/slide26.html', pptx);

    // Chapter 4: Financial Forecast
    // Slide 27: Revenue Forecast with Line Chart
    const { slide: slide27, placeholders: p27 } = await html2pptx('workspace/slide27.html', pptx);
    slide27.addChart(pptx.charts.BAR, [{
        name: "收入预测",
        labels: ["第一年", "第二年", "第三年", "第四年", "第五年"],
        values: [8000, 12000, 18000, 25000, 35000]
    }], { ...p27[0], barDir: 'col', showTitle: true, title: '收入预测(万元)', showLegend: false, showCatAxisTitle: true, catAxisTitle: '年份', showValAxisTitle: true, valAxisTitle: '收入(万元)', valAxisMinVal: 0, valAxisMaxVal: 40000, valAxisMajorUnit: 10000, chartColors: ["1E40AF"] });

    // Slide 28: Cost Structure with Pie Chart
    const { slide: slide28, placeholders: p28 } = await html2pptx('workspace/slide28.html', pptx);
    slide28.addChart(pptx.charts.PIE, [{
        name: "成本结构",
        labels: ["直接材料", "人工成本", "营销费用", "研发费用", "管理费用"],
        values: [45, 15, 15, 10, 10]
    }], { ...p28[0], showPercent: true, showLegend: true, legendPos: 'b', chartColors: ["1E40AF", "3B82F6", "60A5FA", "93C5FD", "BFDBFE"] });

    await html2pptx('workspace/slide29.html', pptx);

    // Slide 30: Conclusion
    await html2pptx('workspace/slide30.html', pptx);

    await pptx.writeFile({ fileName: '热敏打印机市场分析.pptx' });
    console.log('Presentation created: 热敏打印机市场分析.pptx');
}

createPresentation().catch(console.error);

